  TimeoutException({required this.message, this.url});

  @override
  String toString() => 'TimeoutException: $message (url: $url)';
}

/// Represents a discovered IoT device on the local network
class IoTDevice {
  final String ipAddress;
  final int port;
  final String? name;
  final bool usesHttps;

  IoTDevice({
    required this.ipAddress,
    this.port = 80,
    this.name,
    this.usesHttps = false,
  });

  String get baseUrl =>
      '${usesHttps ? 'https' : 'http'}://$ipAddress:$port';
}

/// Generic API response wrapper
