  /// Discover devices on the local network by scanning a subnet
  Future<List<IoTDevice>> discoverDevices({
    String subnet = '192.168.1',
    int port = 80,
    int startRange = 1,
    int endRange = 254,
    Duration timeout = const Duration(seconds: 2),
  }) async {
    final devices = <IoTDevice>[];
    final futures = <Future<void>>[];

    for (int i = startRange; i <= endRange; i++) {
      final ip = '$subnet.$i';
      futures.add(
        _tryDiscoverDevice(ip, port, timeout).then((device) {
          if (device != null) {
            devices.add(device);
          }
        }),
      );
    }

    await Future.wait(futures);
    return devices;
  }

  Future<IoTDevice?> _tryDiscoverDevice(
    String ip,
    int port,
    Duration timeout,
  ) async {
    final device = IoTDevice(ipAddress: ip, port: port);
    try {
      final response = await _request(
        method: 'GET',
        url: '${device.baseUrl}/info',
        timeout: timeout,
        retries: 0,
      );
      if (response.isSuccess) {
        return IoTDevice(
          ipAddress: ip,
          port: port,
          name: response.data?['name'] as String? ?? 'Unknown Device',
        );
      }
    } catch (_) {
      // Device not found or not responding
    }
    return null;
  }

