// Alias for dart:async TimeoutException to avoid conflict
typedef AsyncTimeoutException = async_timeout.TimeoutException;

// We need this import alias to handle the TimeoutException from dart:async
// Since we defined our own TimeoutException class, we use the dart:async one
// in the catch block above via the .timeout() method

/// Example usage demonstrating how to use the HttpService
Future<void> main() async {
  final httpService = HttpService(
    authToken: 'your-initial-auth-token',
  );

  try {
    // ---- Cloud API Examples ----

    // GET request to cloud API
    final usersResponse = await httpService.cloudGet('/api/v1/users');
    if (usersResponse.isSuccess) {
      print('Users: ${usersResponse.data}');
    } else {
      print('Error: ${usersResponse.errorMessage}');
    }

    // POST request to cloud API
    final createResponse = await httpService.cloudPost(
      '/api/v1/devices',
      body: {
        'name': 'Living Room Sensor',
        'type': 'temperature',
      },
    );
    print('Created device: ${createResponse.data}');

    // ---- IoT Device Examples ----

    // Define a local IoT device (HTTP only)
    final thermostat = IoTDevice(
      ipAddress: '192.168.1.100',
      port: 80,
      name: 'Living Room Thermostat',
      usesHttps: false,
    );

    // Define a local IoT device that supports HTTPS
    final secureCamera = IoTDevice(
      ipAddress: '192.168.1.101',
      port: 443,
      name: 'Front Door Camera',
      usesHttps: true,
    );

    // Ping a device
    final isOnline = await httpService.pingDevice(thermostat);
    print('Thermostat online: $isOnline');

    // GET device status
    final statusResponse = await httpService.iotGet(
      thermostat,
      '/api/status',
    );
    if (statusResponse.isSuccess) {
      print('Thermostat status: ${statusResponse.data}');
    }

    // POST command to device
    final commandResponse = await httpService.iotPost(
      thermostat,
      '/api/temperature',
      body: {'target': 22.5},
    );
    print('Command response: ${commandResponse.data}');

    // GET from secure IoT device
    final cameraResponse = await httpService.iotGet(
      secureCamera,
      '/api/snapshot',
    );
    print('Camera response: ${cameraResponse.data}');

    // ---- Device Discovery ----
    print('Scanning network for devices...');
    final devices = await httpService.discoverDevices(
      subnet: '192.168.1',
      port: 80,
      timeout: const Duration(seconds: 1),
    );
    for (final device in devices) {
      print('Found device: ${device.name} at ${device.ipAddress}');
    }

    // ---- Direct Request ----
    final customResponse = await httpService.directRequest(
      method: 'GET',
      url: 'http://192.168.1.50:8080/custom/endpoint',
      timeout: const Duration(seconds: 5),
      retries: 2,
    );
    print('Custom response: ${customResponse.data}');
  } on ApiException catch (e) {
    print('API Error: ${e.message} (Status: ${e.statusCode})');
  } on NetworkException catch (e) {
    print('Network Error: ${e.message}');
  } on TimeoutException catch (e) {
    print('Timeout: ${e.message}');
  } catch (e) {
    print('Unexpected error: $e');
  } finally {
    httpService.dispose();
  }
}